queries.sparql:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasDesigners ?child ; p:hasFashion_Reporters ?parent . } GROUP BY ?child }
  ?child p:name ?name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Fashion_Reporters } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasDesigners ?child ; p:hasFashion_Reporters ?parent . } GROUP BY ?child }
  ?child p:name ?name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Fashion_Reporters } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?fullname ?name WHERE {
  ?fashion_reporters_designers a :Fashion_Reporters_Designers .
  ?designers a :Designers .
  ?fashion_reporters_designers p:hasDesigners ?designers .
  ?fashion_reporters a :Fashion_Reporters .
  ?fashion_reporters_designers p:hasFashion_Reporters ?fashion_reporters .
  ?fashion_reporters p:name ?fullname .
  ?designers p:name ?name .
} }
}
